class Solution:
    def rangeAddQueries(self, n, queries):
        mat = [[0] * n for _ in range(n)]
        for r1, c1, r2, c2 in queries:
            for x in range(r1, r2 + 1):
                for y in range(c1, c2 + 1):
                    mat[x][y] += 1
        return mat

