class Solution:
    def rangeAddQueries(self, n, queries):
        diff = [[0] * (n + 1) for _ in range(n + 1)]
        for r1, c1, r2, c2 in queries:
            diff[r1][c1] += 1
            diff[r1][c2 + 1] -= 1
            diff[r2 + 1][c1] -= 1
            diff[r2 + 1][c2 + 1] += 1
        mat = [[0] * n for _ in range(n)]
        for i in range(n):
            row_running = 0
            for j in range(n):
                row_running += diff[i][j]
                above = mat[i - 1][j] if i > 0 else 0
                mat[i][j] = row_running + above
        return mat

