var rangeAddQueries = function(n, queries) {
    const diff = Array.from({ length: n + 1 }, () => new Array(n + 1).fill(0));
    for (const [r1, c1, r2, c2] of queries) {
        diff[r1][c1] += 1;
        diff[r1][c2 + 1] -= 1;
        diff[r2 + 1][c1] -= 1;
        diff[r2 + 1][c2 + 1] += 1;
    }
    const mat = Array.from({ length: n }, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) {
        let rowRunning = 0;
        for (let j = 0; j < n; j++) {
            rowRunning += diff[i][j];
            const above = i > 0 ? mat[i - 1][j] : 0;
            mat[i][j] = rowRunning + above;
        }
    }
    return mat;
};
